  ('science', '1', 2, '1.shadow', NULL, 'A shadow is made when an object blocks ___.', '["water","wind","light","sound"]', 2, 'When something blocks light, it makes a shadow.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'You need ___ to make a shadow.', '["only darkness","rain","snow","light"]', 3, 'No light means no shadow.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'A shadow is ___ than the bright area around it.', '["wetter","brighter","darker","louder"]', 2, 'A shadow is a dark spot where light is blocked.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'When the sun is high in the sky at noon, shadows are usually ___.', '["invisible always","short","rainbow-colored","very long"]', 1, 'When the sun is overhead, shadows are short.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'Which can make a shadow?', '["Clear water","A solid toy","Clean air","Empty space"]', 1, 'Solid things block light and make shadows.', 10),
  ('science', '1', 2, '1.shadow', NULL, 'Light travels in a ___ line.', '["straight","circle","zigzag","curvy"]', 0, 'Light moves in straight lines.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which object is usually made of metal?', '["A paper book","A spoon","A glass window","A cotton shirt"]', 1, 'Many spoons are made of metal.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material can you see through?', '["Glass","Wood","Brick","Metal"]', 0, 'Glass is clear, so you can see through it.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material is soft and good for a blanket?', '["Rock","Glass","Metal","Cloth"]', 3, 'Cloth is soft and warm, good for blankets.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Rubber is ___.', '["clear like air","made of glass","hard as a rock","stretchy and bendy"]', 3, 'Rubber can stretch and bend.', 10),
  ('science', '1', 2, '1.materials', NULL, 'We often use ___ to build strong bridges.', '["paper","metal","cotton","feathers"]', 1, 'Metal is strong and good for building.', 10),
  ('science', '1', 2, '1.materials', NULL, 'Which material floats easily on water?', '["Wood","A metal nail","A brick","A heavy rock"]', 0, 'Wood is light and floats on water.', 10),
  ('science', '1', 2, '1.sky', NULL, 'Which gives us light during the day?', '["The moon","The sun","A streetlight","The stars"]', 1, 'The sun lights up the day.', 10),
  ('science', '1', 2, '1.sky', NULL, 'We can see many tiny ___ in the night sky.', '["clouds only","suns","stars","rainbows"]', 2, 'Stars sparkle in the night sky.', 10),
  ('science', '1', 2, '1.sky', NULL, 'The moon looks bright because it reflects light from the ___.', '["Earth","streetlights","sun","stars"]', 2, 'The moon has no light of its own; it reflects the sun.', 10),
  ('science', '1', 2, '1.sky', NULL, 'The sun is actually a ___.', '["star","cloud","planet","moon"]', 0, 'The sun is a star that is close to us.', 10),
  ('science', '1', 2, '1.sky', NULL, 'During a clear day, the sky usually looks ___.', '["black","blue","red","green"]', 1, 'The clear daytime sky is blue.', 10),
  ('science', '1', 2, '1.sky', NULL, 'Which looks bigger to us because it is much closer to Earth?', '["A distant planet","The moon","A faraway star","The whole sky"]', 1, 'The moon is close, so it looks big. Stars are far, so they look tiny.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Which part of a plant is usually green and makes food from sunlight?', '["The leaves","The roots","The soil","The seed"]', 0, 'Leaves use sunlight to make food for the plant.', 10),
  ('science', '1', 2, '1.plants', NULL, 'Besides sunlight, plants also need ___ to grow.', '["water","toys","candy","rocks"]', 0, 'Plants need water and sunlight to grow.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby cow is called a ___.', '["kitten","chick","calf","puppy"]', 2, 'A baby cow is a calf.', 10),
  ('science', '1', 2, '1.animalbabies', NULL, 'A baby frog is called a ___.', '["foal","tadpole","joey","cub"]', 1, 'A baby frog hatches as a tadpole and grows legs later.', 10),
  ('science', '1', 2, '1.seasons', NULL, 'In which season do many leaves fall from the trees?', '["Summer","Winter","Spring","Fall"]', 3, 'Leaves drop in the fall (autumn).', 10),
