  ('geography', '1', 2, 'geo.1.directions', NULL, 'What are the four main directions called?', '["One, Two, Three, Four","North, South, East, West","Red, Blue, Green, Yellow","Up, Down, Left, Right"]', 1, 'The four cardinal directions are North, South, East, and West.', 10),
  ('geography', '1', 2, 'geo.1.directions', NULL, 'On a map, which direction is usually at the top?', '["West","North","South","East"]', 1, 'On most maps, North points to the top.', 10),
  ('geography', '1', 2, 'geo.1.directions', NULL, 'The sun rises in the ___.', '["South","East","West","North"]', 1, 'The sun rises in the East and sets in the West.', 10),
  ('geography', '1', 2, 'geo.1.mapkey', NULL, 'The part of a map that explains what the symbols mean is the ___.', '["map key","title page","clock","phone"]', 0, 'A map key (or legend) tells what each symbol stands for.', 10),
  ('geography', '1', 2, 'geo.1.mapkey', NULL, 'A small star on a map often shows a ___.', '["capital city","tree","river","cloud"]', 0, 'A star is a common map symbol for a capital city.', 10),
  ('geography', '1', 2, 'geo.1.mapkey', NULL, 'The compass rose on a map shows the ___.', '["weather","price","time","directions"]', 3, 'A compass rose shows North, South, East, and West.', 10),
  ('geography', '1', 2, 'geo.1.landforms', NULL, 'Which landform is very tall with steep sides?', '["A field","A mountain","A lake","A pond"]', 1, 'A mountain is a tall landform that rises high above the land.', 10),
  ('geography', '1', 2, 'geo.1.landforms', NULL, 'Water that flows in a long path across the land is a ___.', '["mountain","desert","hill","river"]', 3, 'A river is moving water that flows across the land.', 10),
  ('geography', '1', 2, 'geo.1.landforms', NULL, 'A piece of land with water all around it is an ___.', '["island","hill","ocean","valley"]', 0, 'An island has water on every side.', 10),
