  ('history', '1', 2, 'hist.1.longago', NULL, 'Long ago, before phones, people often sent messages by writing ___.', '["letters","text messages","emails","video calls"]', 0, 'Long ago people wrote letters to send news to far-away friends.', 10),
  ('history', '1', 2, 'hist.1.longago', NULL, 'Before electric lights, people lit their homes at night with ___.', '["candles","tablets","TVs","flashlights with batteries"]', 0, 'Long ago, candles and oil lamps gave light at night.', 10),
  ('history', '1', 2, 'hist.1.longago', NULL, 'How can we learn about how people lived long ago?', '["Playing tag","Eating breakfast","Watching cartoons","Old photos and stories"]', 3, 'Old photographs, objects, and stories teach us about the past.', 10),
  ('history', '1', 2, 'hist.1.symbols', NULL, 'What are the colors of the United States flag?', '["Red, white, and blue","Pink and gray","Black and orange","Green and yellow"]', 0, 'The U.S. flag is red, white, and blue.', 10),
  ('history', '1', 2, 'hist.1.symbols', NULL, 'The bald eagle is a famous symbol of the ___.', '["alphabet","moon","ocean","United States"]', 3, 'The bald eagle is the national bird and a symbol of the U.S.', 10),
  ('history', '1', 2, 'hist.1.holidays', NULL, 'On the Fourth of July, the United States celebrates its ___.', '["birthday (Independence Day)","first day of school","new year","harvest"]', 0, 'July 4th is Independence Day, the birthday of the United States.', 10),
  ('history', '1', 2, 'hist.1.holidays', NULL, 'On which holiday do we honor people who served in the military?', '["Earth Day","Pi Day","April Fool''s Day","Veterans Day"]', 3, 'Veterans Day honors people who served in the armed forces.', 10),
  ('history', '1', 2, 'hist.1.longago', NULL, 'Long ago, families washed clothes by hand. Today many people use a ___.', '["telescope","kite","washing machine","skateboard"]', 2, 'Washing machines make cleaning clothes much easier today.', 10),
