  ('history', '1', 2, 'hist.1.holidays', NULL, 'Memorial Day is a holiday that honors ___.', '["famous singers","soldiers who died serving the country","school teachers","the first day of summer"]', 1, 'Memorial Day honors service members who died serving the country.', 10),
  ('civics', '1', 2, 'civ.1.laws', NULL, 'A rule that everyone in a community must follow is called a ___.', '["game","law","song","joke"]', 1, 'Laws are rules that everyone in a community must follow.', 10),
