  ('economics', '1', 2, 'econ.1.needswants', NULL, 'Which group lists only NEEDS?', '["Food, water, and shelter","Stickers and balloons","Toys, candy, and games","Movies and ice cream"]', 0, 'Food, water, and shelter are needs everyone must have.', 10),
