  ('civics', '3', 2, 'civ.3.lawmaking', NULL, 'What should you do if you think a rule is unfair?', '["Do nothing ever","Ignore everyone","Break it secretly","Speak up and ask leaders to change it"]', 3, 'In a fair community, people can speak up to change rules and laws.', 10),
  ('civics', '3', 2, 'civ.3.rights', NULL, 'A ''right'' is something every person is free to ___.', '["have or do","buy only with gold","win in a contest","find in space"]', 0, 'Rights are freedoms that belong to every person.', 10),
  ('civics', '3', 2, 'civ.3.rights', NULL, 'Freedom of speech means you are allowed to ___.', '["never talk","only whisper","speak just one word a day","share your ideas"]', 3, 'Freedom of speech lets people share their ideas and opinions.', 10),
  ('civics', '3', 2, 'civ.3.symbols', NULL, 'The Statue of Liberty is a symbol of ___.', '["freedom","fast food","homework","winter"]', 0, 'The Statue of Liberty stands for freedom and welcome.', 10),
  ('civics', '3', 2, 'civ.3.localgov', NULL, 'Who would you most likely ask to fix a broken park in your town?', '["A farmer in another state","The president alone","A movie star","Local government leaders"]', 3, 'Local government takes care of town services like parks.', 10),
  ('civics', '3', 2, 'civ.3.rights', NULL, 'Freedom of religion means people can ___.', '["only believe one thing","be forced to agree","never have beliefs","choose their own beliefs"]', 3, 'Freedom of religion lets people choose what to believe.', 10),
  ('civics', '3', 2, 'civ.3.lawmaking', NULL, 'Good laws should treat people ___.', '["fairly and equally","differently for fun","unkindly","as a joke"]', 0, 'Fair laws treat all people equally.', 10),
  ('economics', '3', 2, 'econ.3.scarcity', NULL, 'Scarcity means there is ___.', '["not enough for everyone''s wants","no such thing as choices","only candy","too much of everything"]', 0, 'Scarcity is when there isn''t enough to satisfy everyone''s wants.', 10),
  ('economics', '3', 2, 'econ.3.scarcity', NULL, 'Because of scarcity, people must make ___.', '["mountains","noise","rain","choices"]', 3, 'Since we can''t have everything, scarcity forces us to choose.', 10),
  ('economics', '3', 2, 'econ.3.producerconsumer', NULL, 'A person who MAKES or sells goods is a ___.', '["consumer","producer","tourist","citizen"]', 1, 'A producer makes or provides goods and services.', 10),
  ('economics', '3', 2, 'econ.3.producerconsumer', NULL, 'A person who BUYS and uses goods is a ___.', '["explorer","governor","consumer","producer"]', 2, 'A consumer buys and uses goods and services.', 10),
  ('economics', '3', 2, 'econ.3.choices', NULL, 'When you choose one thing, the thing you give up is called the ___.', '["bonus","prize","refund","trade-off"]', 3, 'A trade-off is what you give up when you make a choice.', 10),
  ('economics', '3', 2, 'econ.3.income', NULL, 'The money a person earns from working is called ___.', '["scarcity","income","a service","weather"]', 1, 'Income is the money you earn from a job.', 10),
  ('economics', '3', 2, 'econ.3.scarcity', NULL, 'When a store sells out of a popular item, that is an example of ___.', '["saving","plenty","scarcity","a service"]', 2, 'Running out because there isn''t enough is scarcity.', 10),
  ('economics', '3', 2, 'econ.3.producerconsumer', NULL, 'A bakery that makes and sells cakes is acting as a ___.', '["tourist","consumer","voter","producer"]', 3, 'The bakery produces and sells goods, so it is a producer.', 10),
  ('economics', '3', 2, 'econ.3.income', NULL, 'Money you receive as a gift or allowance is also a kind of ___.', '["scarcity","income","tax","service"]', 1, 'Income is money you receive, including allowance or gifts.', 10),
