  ('history', '5', 2, 'hist.5.revolution', NULL, 'Who was the commander of the American army during the Revolution and later the first president?', '["George Washington","Paul Revere","Abraham Lincoln","Ulysses S. Grant"]', 0, 'George Washington led the Continental Army and became the first president.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'The document that became the plan of government for the United States is the ___.', '["map of Florida","Constitution","weather report","grocery list"]', 1, 'The U.S. Constitution is the plan for the country''s government.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'The first ten amendments to the Constitution are called the ___.', '["Top Ten List","Rule Book","Bill of Rights","Pledge"]', 2, 'The Bill of Rights is the first ten amendments, protecting people''s freedoms.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'Abraham Lincoln was president of the United States during the ___.', '["Great Depression","Civil War","Space Race","Revolution"]', 1, 'Lincoln led the country during the Civil War.', 10),
  ('history', '5', 2, 'hist.5.civilwar', NULL, 'The Emancipation Proclamation, issued by Lincoln, declared freedom for ___.', '["all soldiers","all farmers","the colonies","enslaved people"]', 3, 'The Emancipation Proclamation declared that enslaved people would be free.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'Pioneers traveling west long ago often journeyed in covered ___.', '["subways","airplanes","submarines","wagons"]', 3, 'Pioneers crossed the country in covered wagons.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'The growth of railroads in the 1800s made travel across the country ___.', '["impossible","more expensive than walking","faster","slower"]', 2, 'Railroads let people and goods cross the country much faster.', 10),
  ('history', '5', 2, 'hist.5.founding', NULL, 'The leaders who helped create the United States government are often called the ___.', '["Governors","Explorers","Founding Fathers","Pioneers"]', 2, 'The Founding Fathers helped create the new nation and its government.', 10),
  ('history', '5', 2, 'hist.5.revolution', NULL, 'The famous battle cry warning that British soldiers were coming is linked to ___.', '["Paul Revere''s ride","the gold rush","the first railroad","the moon landing"]', 0, 'Paul Revere rode to warn that British troops were coming.', 10),
  ('history', '5', 2, 'hist.5.expansion', NULL, 'Settlers moving west were looking for new ___.', '["land to live and farm on","video games","shopping malls","airports"]', 0, 'Pioneers moved west seeking land to farm and settle.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'The first ten amendments to the Constitution are called the ___.', '["Top Ten","Rule Book","Bill of Rights","Declaration"]', 2, 'The Bill of Rights is the first ten amendments.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'An ''amendment'' is a ___ to the Constitution.', '["drawing","change or addition","vacation","song"]', 1, 'An amendment is a change or addition to the Constitution.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'The system that lets each branch limit the power of the others is called ___.', '["checks and balances","show and tell","rock and roll","give and take"]', 0, 'Checks and balances keep any one branch from getting too much power.', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'Splitting government into three branches helps make sure no one branch becomes too ___.', '["friendly","powerful","colorful","quiet"]', 1, 'Three branches keep power balanced so no branch becomes too powerful.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Government that serves the WHOLE country is the ___ government.', '["neighborhood","federal (national)","school","city"]', 1, 'The federal government serves the entire country.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'The two parts of Congress are the Senate and the House of ___.', '["Mayors","Governors","Wizards","Representatives"]', 3, 'Congress has two parts: the Senate and the House of Representatives.', 10),
  ('civics', '5', 2, 'civ.5.rights', NULL, 'Serving on a jury and voting are examples of a citizen''s ___.', '["chores at home","civic duties","hobbies","sports"]', 1, 'Voting and jury service are civic duties of citizens.', 10),
  ('civics', '5', 2, 'civ.5.constitution', NULL, 'The introduction to the Constitution is called the ___.', '["Index","Preamble","Appendix","Glossary"]', 1, 'The Preamble is the opening of the Constitution (''We the People…'').', 10),
  ('civics', '5', 2, 'civ.5.checksbalances', NULL, 'The President can reject a law passed by Congress using a ___.', '["vote","song","map","veto"]', 3, 'A veto is the President''s power to reject a law — a check on Congress.', 10),
  ('civics', '5', 2, 'civ.5.levels', NULL, 'Government that serves just one city or town is ___ government.', '["local","world","national","federal"]', 0, 'Local government serves a single city or town.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'A place or system where goods and services are bought and sold is a ___.', '["museum","mountain","memory","market"]', 3, 'A market is where buyers and sellers trade goods and services.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'In a market, the price is set by both buyers and ___.', '["the weather","teachers only","sellers","the moon"]', 2, 'Prices come from the interaction of buyers and sellers.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'A bank is a safe place to keep your money and can pay you ___ on savings.', '["stickers","interest","homework","weather"]', 1, 'Banks keep money safe and can pay interest on savings.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Interest is extra money the bank pays you for ___ your money there.', '["losing","saving","hiding","spending"]', 1, 'Interest is a reward for keeping (saving) money in the bank.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'When people focus on the one job they do best, it is called ___.', '["specialization","budgeting","scarcity","bartering"]', 0, 'Specialization is focusing on what you do best, then trading for the rest.', 10),
  ('economics', '5', 2, 'econ.5.specialization', NULL, 'Countries and people TRADE because no one can produce ___ by themselves.', '["only toys","nothing at all","rain","everything they need"]', 3, 'Trade lets people get goods they don''t or can''t make themselves.', 10),
  ('economics', '5', 2, 'econ.5.taxes', NULL, 'Money people pay to the government to fund services like roads and schools is called ___.', '["interest","tips","allowance","taxes"]', 3, 'Taxes are money paid to the government to pay for public services.', 10),
  ('economics', '5', 2, 'econ.5.banking', NULL, 'Borrowing money that must be paid back, often with extra, is called taking out a ___.', '["loan","tax refund","gift","service"]', 0, 'A loan is borrowed money you repay, usually with interest.', 10),
  ('economics', '5', 2, 'econ.5.market', NULL, 'If many stores sell the same item, they ___ for customers.', '["sleep","vote","compete","hide"]', 2, 'Sellers compete for customers, which can lower prices.', 10),
